.onLoad <- function(libname, pkgname) {
  # Force NULL device on headless systems (including CRAN)
  # This prevents segfaults when rgl tries to access OpenGL in environments
  # without a display server
  if (!interactive() || identical(Sys.getenv("RGL_USE_NULL"), "TRUE")) {
    # Use tryCatch to handle cases where rgl might not be available
    tryCatch(
      rgl::rgl.useNULL(TRUE),
      error = function(e) {
        # Silently ignore errors if rgl is not available
        # This allows the package to load even if rgl is not installed
      }
    )
  }
}

